&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;&amp;#x642D;&amp;#x5EFA;web&amp;#x73AF;&amp;#x5883;-&amp;gt;&amp;#x542F;&amp;#x7528;nginx+mysql+php&amp;#x73AF;&amp;#x5883;&lt;ul&gt;
&lt;li&gt;&lt;p&gt;&amp;#x9047;&amp;#x5230;&amp;#x4E86;&amp;#x4E24;&amp;#x4E2A;&amp;#x95EE;&amp;#x9898;&amp;#xFF1A;&amp;#x627E;&amp;#x4E0D;&amp;#x5230;nginx&amp;#x3001;&amp;#x627E;&amp;#x4E0D;&amp;#x5230;mysqld&amp;#xFF0C;&amp;#x89E3;&amp;#x51B3;&amp;#x529E;&amp;#x6CD5;&amp;#x5F88;&amp;#x7B80;&amp;#x5355;&amp;#xFF0C;ssh&amp;#x5BA2;&amp;#x6237;&amp;#x7AEF;&amp;#x4E2D;&amp;#x8F93;&amp;#x5165;&amp;#x547D;&amp;#x4EE4;&lt;/p&gt;
  &lt;figure class=&#34;highlight shell hljs&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;opkg update&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;opkg install nginx&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;opkg install mysql-server&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

&lt;p&gt;&amp;#x5373;&amp;#x53EF;&amp;#x6B63;&amp;#x5E38;&amp;#x4E0B;&amp;#x8F7D;&amp;#x5B89;&amp;#x88C5;LNMP&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt; &amp;#x8FD9;&amp;#x4E00;&amp;#x6B65;&amp;#x8017;&amp;#x65F6;&amp;#x4E5F;&amp;#x8F83;&amp;#x957F;&amp;#xFF0C;&amp;#x4ECD;&amp;#x9700;&amp;#x8010;&amp;#x5FC3;&amp;#x7B49;&amp;#x5F85;log&amp;#x680F;&amp;#x4E2D;&amp;#x5B8C;&amp;#x6210;&amp;#x7684;&amp;#x4FE1;&amp;#x606F;&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;phpmyadmin&amp;#x4E0B;&amp;#x8F7D;&amp;#x5931;&amp;#x8D25;&amp;#xFF0C;&amp;#x957F;&amp;#x65F6;&amp;#x95F4;&amp;#x5361;&amp;#x5728;&amp;#x4E0B;&amp;#x8F7D;&amp;#x8FDB;&amp;#x7A0B;&amp;#xFF0C;&amp;#x53EF;&amp;#x4ECE;&amp;#x5B98;&amp;#x7F51;&amp;#x624B;&amp;#x52A8;&amp;#x4E0B;&amp;#x8F7D;4.8.3&amp;#x7248;&amp;#x672C;&amp;#xFF08;&amp;#x770B;log&amp;#x680F;&amp;#x4E2D;&amp;#x663E;&amp;#x793A;&amp;#x7684;&amp;#x94FE;&amp;#x63A5;&amp;#x4FE1;&amp;#x606F;&amp;#xFF0C;&amp;#x53EF;&amp;#x80FD;&amp;#x7248;&amp;#x672C;&amp;#x4F1A;&amp;#x6709;&amp;#x6240;&amp;#x4E0D;&amp;#x540C;&amp;#xFF09;&amp;#xFF0C;&amp;#x538B;&amp;#x7F29;&amp;#x5305;&amp;#x540D;&amp;#x79F0;&amp;#x4FEE;&amp;#x6539;&amp;#x4E3A;&lt;code&gt;phpmyadmin.zip&lt;/code&gt;&amp;#x540E;&amp;#x4F20;&amp;#x5165;&amp;#x8DEF;&amp;#x7531;&amp;#x5668;&lt;code&gt;\opt\wwwroot&lt;/code&gt;&amp;#x8DEF;&amp;#x5F84;&amp;#x5373;&amp;#x53EF;&amp;#x6B63;&amp;#x5E38;&amp;#x89E3;&amp;#x538B;&amp;#x8FD0;&amp;#x884C;&lt;/li&gt;
&lt;li&gt;&amp;#x4E00;&amp;#x5207;&amp;#x51C6;&amp;#x5907;&amp;#x597D;&amp;#x540E;&amp;#x8DEF;&amp;#x7531;&amp;#x5668;log&amp;#x680F;&amp;#x4E2D;&amp;#x53D1;&amp;#x73B0;mysql&amp;#x4ECD;&amp;#x4E0D;&amp;#x505C;&amp;#x91CD;&amp;#x542F;&amp;#xFF0C;ssh&amp;#x7EC8;&amp;#x7AEF;&amp;#x8FD0;&amp;#x884C;mysql&amp;#x540E;&amp;#x53D1;&amp;#x73B0;&amp;#x7F3A;&amp;#x5C11;mysql&amp;#x5E93;&amp;#xFF0C;&amp;#x5927;&amp;#x6982;&amp;#x662F;&amp;#x672C;&amp;#x5730;&amp;#x6570;&amp;#x636E;&amp;#x5E93;&amp;#x521D;&amp;#x59CB;&amp;#x5316;&amp;#x672A;&amp;#x5B8C;&amp;#x6210;&amp;#x7684;&amp;#x539F;&amp;#x56E0;&amp;#xFF0C;&amp;#x627E;&amp;#x5230;&lt;code&gt;mysql&lt;/code&gt;&amp;#x4E0B;&amp;#x7684;&lt;code&gt;bin&lt;/code&gt;&amp;#x76EE;&amp;#x5F55;&amp;#xFF0C;&amp;#xFF08;padavan&amp;#x7CFB;&amp;#x7EDF;&amp;#x4E3A;&lt;code&gt;/opt/bin&lt;/code&gt;&amp;#x76EE;&amp;#x5F55;&amp;#xFF09;&amp;#x8FD0;&amp;#x884C;&lt;code&gt;mysql_install_db&lt;/code&gt;&amp;#xFF0C;&amp;#x91CD;&amp;#x65B0;&amp;#x521D;&amp;#x59CB;&amp;#x5316;mysql&amp;#x5E93;&amp;#x540E;&amp;#x6062;&amp;#x590D;&amp;#x6B63;&amp;#x5E38;&lt;/li&gt;
&lt;li&gt;&amp;#x51E0;&amp;#x6B21;&amp;#x8FD0;&amp;#x884C;&amp;#x540E;&amp;#x53D1;&amp;#x73B0;&amp;#x6709;&amp;#x65F6;phpmyadmin&amp;#x65E0;&amp;#x6CD5;&amp;#x8FDB;&amp;#x5165;&amp;#xFF0C;&amp;#x8BD5;&amp;#x4E86;&amp;#x8BD5;&amp;#x628A;phpmyadmin config&amp;#x4E2D;&amp;#x7684;&lt;code&gt;$cfg[&amp;apos;Servers&amp;apos;][$i][&amp;apos;host&amp;apos;] = &amp;apos;localhost&amp;apos;;&lt;/code&gt;&amp;#x66F4;&amp;#x6539;&amp;#x4E3A;&lt;code&gt;$cfg[&amp;apos;Servers&amp;apos;][$i][&amp;apos;host&amp;apos;] = &amp;apos;127.0.0.1&amp;apos;;&lt;/code&gt;&amp;#x540E;&amp;#x8FD0;&amp;#x884C;&amp;#x6B63;&amp;#x5E38;&amp;#x3002;&lt;/li&gt;
&lt;/ol&gt;
&lt;h2&gt;&lt;a href=&#34;#hou-ji&#34; class=&#34;header-anchor&#34;&gt;#&lt;/a&gt;&lt;span id=&#34;hou-ji&#34;&gt;&amp;#x540E;&amp;#x8BB0;&lt;/span&gt;&lt;/h2&gt;&lt;p&gt;&amp;#x4F7F;&amp;#x7528;&amp;#x6548;&amp;#x679C;&lt;br&gt;&lt;img src=&#34;/img/Lychee.gif&#34; alt=&#34;web view&#34;&gt;&lt;/p&gt;
&lt;blockquote&gt;
&lt;p&gt;gif&amp;#x5F55;&amp;#x5236;&amp;#x538B;&amp;#x7F29;&amp;#x539F;&amp;#x56E0;&amp;#xFF0C;&amp;#x56FE;&amp;#x7247;&amp;#x5931;&amp;#x771F;&amp;#x4E25;&amp;#x91CD;&amp;#xFF0C;&amp;#x5B9E;&amp;#x9645;&amp;#x67E5;&amp;#x770B;&amp;#x65F6;&amp;#x56FE;&amp;#x7247;&amp;#x5206;&amp;#x8FA8;&amp;#x7387;&amp;#x4FDD;&amp;#x6301;&amp;#x56FE;&amp;#x7247;&amp;#x6E90;&amp;#x5206;&amp;#x8FA8;&amp;#x7387;&lt;br&gt;&lt;em&gt;&amp;#x6B64;&amp;#x7BC7;&amp;#x53EA;&amp;#x505A;&amp;#x8BB0;&amp;#x5F55;&amp;#x7528;&amp;#xFF0C;&amp;#x4EE5;&amp;#x65B9;&amp;#x4FBF;&amp;#x518D;&amp;#x6298;&amp;#x817E;&amp;#x5176;&amp;#x4ED6;&amp;#x529F;&amp;#x80FD;&lt;/em&gt;&lt;/p&gt;
&lt;/blockquote&gt;

 &lt;p&gt;For some unknown reasons, the ipv6 got offline once in a while. After rebooting, it turned just fine. I need ipv6 to do torrenting. So here comes the demand for a script to check my ipv6 availability.&lt;/p&gt;
&lt;span id=&#34;more&#34;&gt;&lt;/span&gt;

&lt;figure class=&#34;highlight shell hljs&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;hljs-meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;hljs-bash&#34;&gt;!/bin/sh&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;hljs-meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;hljs-bash&#34;&gt;ipv6 check script, reboot &lt;span class=&#34;hljs-keyword&#34;&gt;if&lt;/span&gt; fails&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;hljs-meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;hljs-bash&#34;&gt;url=&amp;lt;an ipv6-only site&amp;gt;  || delete the &lt;span class=&#34;hljs-string&#34;&gt;&amp;quot;#&amp;quot;&lt;/span&gt; to take effect or replace &lt;span class=&#34;hljs-string&#34;&gt;&amp;apos;$url&amp;apos;&lt;/span&gt; with actual url down &lt;span class=&#34;hljs-keyword&#34;&gt;in&lt;/span&gt; the corresponding &lt;span class=&#34;hljs-built_in&#34;&gt;command&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;n=4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;timeout=1000&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;logger -t &amp;quot;[ipv6]&amp;quot; &amp;quot;check BEGIN&amp;quot;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;ping -c $n -W $timeout $url&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;if [ $? != 0 ];then&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    logger -t &amp;quot;[ipv6]&amp;quot; &amp;quot;failed, try reboot&amp;quot;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    reboot&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;else&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    logger -t &amp;quot;[ipv6]&amp;quot; &amp;quot;working fine!&amp;quot;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;fi&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;exit 0&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

&lt;p&gt;What it does is obvious. Noted that &lt;code&gt;logger -t&lt;/code&gt; needs two strings to display information in the log area. The script above displays informations as follows.&lt;/p&gt;
&lt;figure class=&#34;highlight plaintext hljs&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;Oct 21 17:40:00 [ipv6]:  check BEGIN&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;Oct 21 17:40:03 [ipv6]:  working fine&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

&lt;p&gt;However, the log area could be filled with these two information, which is not ideal. &lt;code&gt;logger -t&lt;/code&gt; sentence could be deleted after testing.&lt;/p&gt;
&lt;h2&gt;&lt;a href=&#34;#settings&#34; class=&#34;header-anchor&#34;&gt;#&lt;/a&gt;&lt;span id=&#34;settings&#34;&gt;Settings&lt;/span&gt;&lt;/h2&gt;&lt;ol&gt;
&lt;li&gt;&lt;p&gt;Check &lt;code&gt;Advaced settings&lt;/code&gt;-&lt;code&gt;System settings&lt;/code&gt;-&lt;code&gt;Services&lt;/code&gt;-&lt;code&gt;Enable SSH&lt;/code&gt;. SSH might not work properly on windows due to some reason about porting. Open the corresponding ports on windows should be the solution here.&lt;/p&gt;
 &lt;figure class=&#34;highlight bash hljs&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;ssh admin@192.168.123.1&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;/li&gt;
&lt;li&gt;&lt;p&gt;Change directory to &lt;code&gt;/etc/storage/&lt;/code&gt;. Files in other directories will be deleted after rebooting. We don&amp;apos;t want our script to vanish, of course.&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;&lt;p&gt;&lt;code&gt;vi ipv6_check.sh&lt;/code&gt;. Create a .sh script, and save the code above inside. The operations of vi is somewhat different from how we operate on windows.&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;&lt;p&gt;The script is not written into the ROM if you did not run the mtd_storage script, because of some settings of Padavan firmware.&lt;br&gt; run &lt;code&gt;/sbin/mtd_storage.sh save&lt;/code&gt; to save the modification.&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;&lt;p&gt;Run script ragularly.&lt;br&gt; &lt;code&gt;system settings&lt;/code&gt;-&lt;code&gt;Services&lt;/code&gt;-&lt;code&gt;cron&lt;/code&gt;&lt;br&gt; Input &lt;code&gt;*/10 * * * * /etc/storage/ipv6_check.sh&lt;/code&gt; in the Cron tab to run the script every 10 minutes.&lt;/p&gt;
&lt;/li&gt;
&lt;/ol&gt;

 &lt;p&gt;&amp;#x4E0D;&amp;#x77E5;&amp;#x9053;&amp;#x4EC0;&amp;#x4E48;&amp;#x539F;&amp;#x56E0;&amp;#xFF0C;ipv6&amp;#x603B;&amp;#x662F;&amp;#x9694;&amp;#x4E00;&amp;#x6BB5;&amp;#x65F6;&amp;#x95F4;&amp;#x5C31;&amp;#x6389;&amp;#x7EBF;&amp;#xFF0C;&amp;#x91CD;&amp;#x542F;&amp;#x8DEF;&amp;#x7531;&amp;#x5668;&amp;#x540E;&amp;#x53C8;&amp;#x6062;&amp;#x590D;&amp;#x6B63;&amp;#x5E38;&amp;#x3002;&amp;#x53C8;&amp;#x56E0;&amp;#x4E3A;&amp;#x4E2A;&amp;#x4EBA;&amp;#x6709;pt&amp;#x505A;&amp;#x79CD;&amp;#x9700;&amp;#x6C42;&amp;#xFF0C;ipv6&amp;#x53C8;&amp;#x662F;&amp;#x4E0D;&amp;#x53EF;&amp;#x6216;&amp;#x7F3A;&amp;#x7684;&amp;#x6761;&amp;#x4EF6;&amp;#xFF0C;&amp;#x6240;&amp;#x4EE5;&amp;#x5199;&amp;#x4E2A;&amp;#x7B80;&amp;#x5355;&amp;#x7684;&amp;#x811A;&amp;#x672C;&amp;#xFF0C;&amp;#x5F53;ipv6&amp;#x53C8;&amp;#x65AD;&amp;#x7EBF;&amp;#x65F6;&amp;#x81EA;&amp;#x52A8;&amp;#x91CD;&amp;#x542F;&amp;#x8DEF;&amp;#x7531;&amp;#x5668;&lt;/p&gt;
&lt;span id=&#34;more&#34;&gt;&lt;/span&gt;

&lt;figure class=&#34;highlight shell hljs&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;hljs-meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;hljs-bash&#34;&gt;!/bin/sh&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;hljs-meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;hljs-bash&#34;&gt;ipv6 check script, reboot &lt;span class=&#34;hljs-keyword&#34;&gt;if&lt;/span&gt; fails&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;hljs-meta&#34;&gt;#&lt;/span&gt;&lt;span class=&#34;hljs-bash&#34;&gt;url=&amp;lt;an ipv6-only site&amp;gt;  || delete the &lt;span class=&#34;hljs-string&#34;&gt;&amp;quot;#&amp;quot;&lt;/span&gt; to take effect or replace &lt;span class=&#34;hljs-string&#34;&gt;&amp;apos;$url&amp;apos;&lt;/span&gt; with actual url down &lt;span class=&#34;hljs-keyword&#34;&gt;in&lt;/span&gt; the corresponding &lt;span class=&#34;hljs-built_in&#34;&gt;command&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;n=4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;timeout=1000&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;logger -t &amp;quot;[ipv6]&amp;quot; &amp;quot;check BEGIN&amp;quot;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;ping -c $n -W $timeout $url&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;if [ $? != 0 ];then&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    logger -t &amp;quot;[ipv6]&amp;quot; &amp;quot;failed, try reboot&amp;quot;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    reboot&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;else&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    logger -t &amp;quot;[ipv6]&amp;quot; &amp;quot;working fine!&amp;quot;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;fi&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;exit 0&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

&lt;p&gt;&amp;#x811A;&amp;#x672C;&amp;#x5185;&amp;#x5BB9;&amp;#x4E00;&amp;#x76EE;&amp;#x4E86;&amp;#x7136;&amp;#xFF0C;&amp;#x9700;&amp;#x8981;&amp;#x6CE8;&amp;#x610F;&amp;#x7684;&amp;#x4E00;&amp;#x70B9;&amp;#xFF0C;&lt;code&gt;logger -t&lt;/code&gt;&amp;#x5728;log&amp;#x4E2D;&amp;#x5199;&amp;#x5165;&amp;#x4FE1;&amp;#x606F;&amp;#x65F6;&amp;#x9700;&amp;#x8981;&amp;#x4E24;&amp;#x4E2A;&amp;#x5B57;&amp;#x7B26;&amp;#x4E32;&amp;#x4F5C;&amp;#x4E3A;&amp;#x8F93;&amp;#x5165;&amp;#xFF0C;&amp;#x5982;&amp;#x4E0A;&amp;#x6587;&amp;#x7684;&amp;#x8BED;&amp;#x53E5;&amp;#x8FD0;&amp;#x884C;&amp;#x540E;&amp;#x5728;padavan&amp;#x7BA1;&amp;#x7406;&amp;#x9762;&amp;#x677F;&amp;#x7684;log&amp;#x663E;&amp;#x793A;&amp;#x5982;&amp;#x4E0B;&amp;#xFF1A;&lt;/p&gt;
